SELECT 'home', 'jhipster-security-platform', 'Home', 'global.menu.home', NULL, NULL, '/', 'pi pi-home', 10
WHERE NOT EXISTS (
    SELECT 1 FROM sec_menu_definition WHERE app_name = 'jhipster-security-platform' AND menu_id = 'home'
);

